using System;

class Dog {
    public string Name;
    public int Age;

    public void Bark() {
        Console.WriteLine($"{Name} says: Woof!");
    }
}

class Program {
    static void Main() {
        Dog rex = new Dog();
        rex.Name = "Rex";
        rex.Age = 3;
        rex.Bark();
        Console.WriteLine($"{rex.Name} is {rex.Age} years old");
    }
}

using System;

class Point {
    public double X;
    public double Y;

    public Point(double x, double y) {
        X = x;
        Y = y;
    }

    public double DistanceFromOrigin() {
        return Math.Sqrt(X * X + Y * Y);
    }
}

class Program {
    static void Main() {
        var p = new Point(3, 4);
        Console.WriteLine($"({p.X}, {p.Y})");
        Console.WriteLine($"distance: {p.DistanceFromOrigin()}");
    }
}

using System;

class Person {
    private string name;
    private int age;

    public Person(string name, int age) {
        this.name = name; // this.name = field, name = parameter
        this.age = age;
    }

    public string Describe() {
        return $"{this.name} is {this.age}";
    }
}

class Program {
    static void Main() {
        var p = new Person("Alice", 30);
        Console.WriteLine(p.Describe());
    }
}

using System;

class Rectangle {
    public double Width, Height;

    public Rectangle(double width, double height) {
        Width = width; Height = height;
    }
    public Rectangle(double side) : this(side, side) {} // square

    public double Area() => Width * Height;
}

class Program {
    static void Main() {
        var rect = new Rectangle(6, 4);
        var square = new Rectangle(5);
        Console.WriteLine($"rect: {rect.Area()}");
        Console.WriteLine($"square: {square.Area()}");
    }
}

using System;

class BankAccount {
    private decimal balance = 0;

    public void Deposit(decimal amount) {
        if (amount <= 0) throw new ArgumentException("Positive amounts only");
        balance += amount;
    }

    public bool Withdraw(decimal amount) {
        if (amount > balance) return false;
        balance -= amount;
        return true;
    }

    public decimal Balance => balance;
}

class Program {
    static void Main() {
        var account = new BankAccount();
        account.Deposit(100);
        Console.WriteLine(account.Withdraw(30));
        Console.WriteLine(account.Balance);
    }
}

using System;

class Counter {
    private static int count = 0;

    public Counter() { count++; }
    public static int Count => count;
}

class Program {
    static void Main() {
        new Counter();
        new Counter();
        new Counter();
        Console.WriteLine(Counter.Count);
    }
}

using System;

class Temperature {
    private double celsius;
    public Temperature(double c) { celsius = c; }
    public override string ToString() => $"{celsius}°C ({celsius * 9/5 + 32:F1}°F)";
}

class Program {
    static void Main() {
        var t = new Temperature(100);
        Console.WriteLine(t);
        Console.WriteLine($"Temp: {t}");
    }
}

using System;

class Config {
    public string Host { get; set; } = "localhost";
    public int Port { get; set; } = 80;
    public bool Debug { get; set; } = false;
}

class Program {
    static void Main() {
        var cfg = new Config { Host = "example.com", Port = 443, Debug = true };
        Console.WriteLine($"{cfg.Host}:{cfg.Port} debug={cfg.Debug}");
    }
}
